text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트가 통과하는 경우 공개 릴리스 목표는 금요일 15:00 KST로 한다.",
        "certainty": "confirmed"
      },
      {
        "topic": "packageName 불일치 대응",
        "decision": "packageName 불일치가 발생하면 먼저 package config를 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다.",
        "certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경하자",
        "result": "rejected",
        "notes": "논의 후 기각됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "internal_only",
        "notes": "최종 공개 릴리스 결정이 아니라 내부 스트레치 목표로만 언급됨"
      },
      {
        "goal": "README 설치 절차를 목요일까지 가능하면 검토",
        "status": "best_effort",
        "notes": "희망 일정만 언급되었고 담당자는 지정되지 않음"
      }
    ],
    "non_decisions": [
      {
        "topic": "README install steps 검토",
        "state": "필요성은 언급되었으나 담당자 미지정, 확정 운영 결정 아님"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로가 릴리스를 지연시킬 수 있음",
        "certainty": "confirmed"
      },
      {
        "risk": "README 설치 절차가 오래되었으면 릴리스 노트가 사용자에게 오해를 줄 수 있음",
        "certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?",
        "status": "open"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?",
        "status": "open"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트 작성",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 게시한 뒤 생성된 tarball 경로 확인",
      "due": "미정",
      "status": "confirmed",
      "source_certainty": "explicit"
    },
    {
      "owner": null,
      "task": "README install steps 검토",
      "due": "목요일까지 가능하면",
      "status": "unassigned",
      "source_certainty": "explicit"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 스모크 테스트 결과가 금요일 10:00 KST까지 공유되었는지 확인",
      "스모크 통과 여부에 따라 금요일 15:00 KST 공개 릴리스 목표 유지 가능 여부 확인",
      "Doyun의 failure triage note가 금요일 12:00 KST까지 action_items.md에 반영되었는지 확인",
      "Minjun 결과 게시 이후 Hara의 tarball 경로 확인 결과를 점검",
      "README install steps 검토 담당자를 별도로 지정할지 확인",
      "최종 릴리스 승인 권한자에 대한 답을 확보",
      "릴리스 노트에 수요일 내부 스트레치 목표를 언급할지 결정"
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 관련 사실",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구사항",
      "지정되지 않은 담당자",
      "명시되지 않은 마감일"
    ]
  },
  "non_invention_rules": [
    "인라인 공개용 synthetic fixture에 있는 정보만 사용한다.",
    "확정 결정과 기각된 제안, 내부 스트레치 목표, 리스크, 오픈 질문을 서로 구분한다.",
    "고객, 예산, 보안, 장애, 법무, 담당자, 마감일 관련 미기재 사실을 추가하지 않는다.",
    "담당자 또는 기한이 명시되지 않은 항목은 null, 미정, 또는 unassigned로 유지한다.",
    "수요일 릴리스는 확정 일정이 아니라 내부 스트레치 목표로만 기록한다."
  ]
}
